UPDATE notice_reply 
SET reply = #{reply}, updateDate = SYSDATE
WHERE rno = #{rno}

mapper.select:

SELECT * FROM (
  SELECT /*+ INDEX_DESC(nr idx_notice_reply) */
         ROWNUM rn, nr.*
  FROM notice_reply nr
  WHERE notice_id = #{notice_id}
    AND ROWNUM <= #{cri.pageNum} * #{cri.amount}
)
WHERE rn > (#{cri.pageNum} - 1) * #{cri.amount}
